import{_ as s,a as n,b as p}from"./chunks/2025-08-12_194246_5856210.3540283832065939.DJa98GIr.js";import{_ as l,o as e,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const r="/media/202508/2025-08-07_172038_0472400.7986562438211805.png",o="/media/202508/2025-08-12_093611_5127360.24133702518002675.png",c="/media/202508/2025-08-12_093449_2312040.7175377993905877.png",_="/media/202508/2025-08-12_094419_7162050.9769175800818402.png",u="/media/202508/2025-08-12_094444_2597840.9326632257308511.png",m="/media/202508/2025-08-12_191842_7644770.4737906868541455.png",d="/media/202508/2025-08-12_192349_5810370.3654981502618089.png",h="/media/202508/2025-08-12_194231_8228770.8860112478315885.png",b="/media/202508/2025-08-12_193821_4874020.12752165493357404.png",g="/media/202508/2025-08-12_194514_4364770.9909628877013154.png",$=JSON.parse('{"title":"语义模型配置","description":"","frontmatter":{"title":"语义模型配置"},"headers":[],"relativePath":"app-config/semantic-model.md","filePath":"app-config/semantic-model.md","lastUpdated":null}'),x={name:"app-config/semantic-model.md"};function q(f,a,k,P,v,I){return e(),t("div",null,[...a[0]||(a[0]=[i('<p>语义模型配置概述</p><p>语义模型配置是AIUI极速超拟人交互类应用提供的配置项目，主要给开发者提供传统语义技能（官方技能、问答库）、大模型语义功能模块（文档问答库、智能体、联网搜索）相关能力配置选项。</p><p>平台分类如下：</p><p><strong>- 添加工具</strong></p><p><strong>- 搜索设置</strong></p><h2 id="_1-添加工具" tabindex="-1">1.添加工具 <a class="header-anchor" href="#_1-添加工具" aria-label="Permalink to &quot;1.添加工具&quot;">​</a></h2><h3 id="_1-1-问答" tabindex="-1">1.1. 问答 <a class="header-anchor" href="#_1-1-问答" aria-label="Permalink to &quot;1.1. 问答&quot;">​</a></h3><p>该配置项是给极速链路配置自定义大模型链路的<strong>文档问答</strong>。 点击“添加”，可以配置当前账号下创建并发布好的文档问答，另外开发者也可以配置文档问答在服务链路的集成策略【针对所有文档问答生效】：</p><ul><li>检索方法 <ul><li>单向量召回</li><li>多路召回</li></ul></li><li>相关性阈值</li></ul><p>知识说明</p><p>1、相关性就是知识片段和用户问题的匹配程度，数值在 0 到 1 之间。这个值越高，说明这个知识片段越有可能帮你答好问题。</p><p>2、检索方法就是计算相关性的方法。单向量召回是靠算语义向量的相似度来得出结果；多路召回则是把语义向量、关键词等多种方式的相似度合起来计算。</p><p>为了筛选出足够匹配的知识片段，会设定一个 “相关性阈值”—— 比如阈值设为 0.6，就意味着只保留相关性数值≥0.6 的知识片段，低于这个值的会被排除，避免不相关的知识干扰回答。</p><p><img src="'+r+'" alt="" title="null"><img src="'+o+'" alt="" title="null"><img src="'+c+'" alt="" title="null"></p><h3 id="_1-2-智能体" tabindex="-1">1.2. 智能体 <a class="header-anchor" href="#_1-2-智能体" aria-label="Permalink to &quot;1.2. 智能体&quot;">​</a></h3><p>该配置项是给极速链路配置自定义大模型链路的<strong>新版智能体</strong>。 点击“添加”，可以配置当前账号下创建并发布好的新版智能体，点击“创建智能体”也可以跳转到智能体开发界面进行自定义智能体开发。</p><p>知识说明</p><p>1、旧版智能体：仅提供意图匹配能力，开发者编辑时仅提供语料设置</p><p>2、新版智能体：除提供意图匹配能力，开发者可以按照业务需要进行节点能力模块自定义编辑。与目前主流智能体开发方式基本保持一致</p><p><img src="'+_+'" alt="" title="null"><img src="'+u+'" alt="" title="null"></p><h3 id="_1-3-技能" tabindex="-1">1.3. 技能 <a class="header-anchor" href="#_1-3-技能" aria-label="Permalink to &quot;1.3. 技能&quot;">​</a></h3><p>该配置项是给极速链路配置传统语义技能能力，支持类型有：</p><ul><li>官方技能</li><li>自定义技能</li><li>语句问答</li><li>关键词问答</li></ul><p>并且还支持进行特性设置，如自定义技能或自定义语句问答的阈值设置、关键词过滤、语义敏感词、精简协议</p><h4 id="_1-3-1-技能配置" tabindex="-1">1.3.1. 技能配置 <a class="header-anchor" href="#_1-3-1-技能配置" aria-label="Permalink to &quot;1.3.1. 技能配置&quot;">​</a></h4><p>点击“添加”，可在当前应用的情景模式下配置需要的技能。</p><p><img src="'+m+'" alt="示例图片"><img src="'+d+'" alt="示例图片"></p><h4 id="_1-3-2-自定义技能阈值设置" tabindex="-1">1.3.2. 自定义技能阈值设置 <a class="header-anchor" href="#_1-3-2-自定义技能阈值设置" aria-label="Permalink to &quot;1.3.2. 自定义技能阈值设置&quot;">​</a></h4><p>在自定义技能添加界面，勾选自定义技能后，点击技能下的设置图标进行设置，注意支持的技能类型： <strong>自定义私有技能、自定义语句问答</strong> 自定义阈值主要是为了做技能匹配度调节的，可以根据实际需要(模糊匹配度和误识别两个维度)综合考虑设置。 AIUI技能实际触发的模糊匹配程度，可以查看技能json中的source字段取值，可以参考该取值进行自定义技能阈值调整。</p><ul><li>技能阈值越高：技能对出发的语句格式要求越严（模糊匹配越低，不容易误识别）</li><li>技能阈值越低：技能对出发的语句格式要求越送（模糊匹配越高，容易误识别）</li></ul><p><img src="'+s+'" alt="示例图片"><img src="'+n+`" alt="示例图片"></p><h4 id="_1-3-3-技能设置" tabindex="-1">1.3.3. 技能设置 <a class="header-anchor" href="#_1-3-3-技能设置" aria-label="Permalink to &quot;1.3.3. 技能设置&quot;">​</a></h4><p>技能配置后，还可以点击“设置”进行一些高级能力配置，开发者按需设置。</p><ul><li><p><strong>关键词过滤</strong> 过滤识别结果中的关键词，不进行语义理解。常用于过滤唤醒词 比如：唤醒词是“小飞小飞” <strong>过滤前</strong>：“小飞小飞，你好“ <strong>过滤后</strong>：“你好“</p></li><li><p><strong>语义敏感词过滤</strong> 给用户回复的信息中包含敏感信息，可以通过设置过滤掉。支持自定义增加。 注意： 到触发语义敏感词过滤时，固定响应：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  answer: {</span></span>
<span class="line"><span>      text: &quot;文明社会，请文明用语。&quot;,</span></span>
<span class="line"><span>      topic: &quot;&quot;,</span></span>
<span class="line"><span>      type: &quot;T&quot;</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  operation: &quot;ANSWER&quot;,</span></span>
<span class="line"><span>  rc: 0,</span></span>
<span class="line"><span>  service: &quot;forbidden&quot;,</span></span>
<span class="line"><span>  sid: &quot;xxxxxxxxx&quot;,</span></span>
<span class="line"><span>  state: null,</span></span>
<span class="line"><span>  text: &quot;xxx&quot;,</span></span>
<span class="line"><span>  uuid: &quot;xxxxxxxxx&quot;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>特别说明：极速交互链路本身在服务层面各个模组的输入输出都是有单独的安全审核服务进行监控的。</p></li><li><p><strong>精简协议</strong> 简化结构化语义，将技能结果分为：媒资类和播报类。默认关闭。 将多个技能精简成一种输出协议，大大降低技能适配工作。适用于无屏设备。</p></li></ul><p><img src="`+h+'" alt="示例图片"><img src="'+p+'" alt="示例图片"></p><h2 id="_2-搜索设置" tabindex="-1">2.搜索设置 <a class="header-anchor" href="#_2-搜索设置" aria-label="Permalink to &quot;2.搜索设置&quot;">​</a></h2><h3 id="_2-1-搜索引擎" tabindex="-1">2.1. 搜索引擎 <a class="header-anchor" href="#_2-1-搜索引擎" aria-label="Permalink to &quot;2.1. 搜索引擎&quot;">​</a></h3><p>该项提供大模型联网搜索能力项，默认是关闭的，开发者可以自行进行开启。 当开启后用户进行语音交互时，当服务判断需要进行搜索时，会调用联网服务进行信息搜索，然后大模型对搜索的信息进行总结答复。</p><p><img src="'+b+'" alt="" title="null"></p><h3 id="_2-2-知识溯源" tabindex="-1">2.2. 知识溯源 <a class="header-anchor" href="#_2-2-知识溯源" aria-label="Permalink to &quot;2.2. 知识溯源&quot;">​</a></h3><p>该能力项主要是控制大模型服务结果下发的，通常作为服务链路中加载文档问答或联网搜索获取的知识点，内容比较多，默认是不下发的。当开发者需要了解大模型回复的内容从哪里获取的时候，可以开启该能力项，开启后AIUI服务在交互时，会新增下发 cbm_knowledge 结果。</p><p><img src="'+g+'" alt="" title="null"></p>',42)])])}const S=l(x,[["render",q]]);export{$ as __pageData,S as default};
